#include <bits/stdc++.h>
using namespace std;
const int N=20;
int n;
double a[N][2];
double dp[1<<15][N],b[N][N],ans=0x3f3f3f3f;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i][0]>>a[i][1];
	memset(dp,127,sizeof(dp));
	a[0][0]=0,a[0][1]=0;
	for(int i=0;i<=n;i++)
	{
		for(int j=i+1;j<=n;j++)
		{
			b[j][i]=b[i][j]=sqrt((a[i][0]-a[j][0])*(a[i][0]-a[j][0])+(a[i][1]-a[j][1])*(a[i][1]-a[j][1]));
		}
	}
	for(int i=1;i<=n;i++)
	{
		dp[(1<<(i-1))][i]=b[0][i];
	}
	for(int i=1;i<(1<<n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			if(!((i>>(j-1))%2))continue;
			for(int k=1;k<=n;k++)
			{
				if(j==k||(!(i>>(k-1)))) continue;
				dp[i][j]=min(dp[i][j],dp[i-(1<<(j-1))][k]+b[k][j]);
			}
		}
	}
	for(int i=1;i<=n;i++) 
	{
		ans=min(ans,dp[(1<<n)-1][i]);
	}
	printf("%.2f",ans);
	return 0;
}
